import{_ as a,o as t,c as i,a2 as r}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"ADR 与决策记录","description":"","frontmatter":{"title":"ADR 与决策记录","stage":"intermediate","direction":"product","tags":["product","adr","decision-record","architecture"]},"headers":[],"relativePath":"02-product/notes/05-prd-expression/07-adr-decision-records.md","filePath":"02-product/notes/05-prd-expression/07-adr-decision-records.md","lastUpdated":null}'),s={name:"02-product/notes/05-prd-expression/07-adr-decision-records.md"};function n(d,e,l,o,h,c){return t(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="adr-与决策记录-保存重要选择的上下文与后果" tabindex="-1">ADR 与决策记录：保存重要选择的上下文与后果 <a class="header-anchor" href="#adr-与决策记录-保存重要选择的上下文与后果" aria-label="Permalink to &quot;ADR 与决策记录：保存重要选择的上下文与后果&quot;">​</a></h1><p>Architecture Decision Record 记录一个影响系统结构、关键质量属性或难以逆转的选择。它至少包含上下文、候选方案、决定、理由、后果和状态。多个 ADR 组成 append-only 决策日志。</p><h2 id="一、什么值得写-adr" tabindex="-1">一、什么值得写 ADR <a class="header-anchor" href="#一、什么值得写-adr" aria-label="Permalink to &quot;一、什么值得写 ADR&quot;">​</a></h2><p>满足以下任一项通常值得记录：引入长期依赖；改变模块或数据边界；发布公共接口；影响安全、可用性、性能或合规；迁移成本高；团队存在多个合理方案。</p><p>局部变量名、容易撤销的实现细节不需要 ADR。完整接口设计、迁移步骤和操作手册可以链接到 ADR，但不能把 ADR 写成巨大设计文档。</p><h2 id="二、adr-与相邻工件" tabindex="-1">二、ADR 与相邻工件 <a class="header-anchor" href="#二、adr-与相邻工件" aria-label="Permalink to &quot;二、ADR 与相邻工件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工件</th><th>回答</th><th>生命周期</th></tr></thead><tbody><tr><td>PRD</td><td>为什么解决、为谁、规则与范围</td><td>随产品迭代</td></tr><tr><td>Design doc</td><td>方案如何工作、接口和时序</td><td>实现期持续更新</td></tr><tr><td>ADR</td><td>在当时约束下为何选择 A 而非 B</td><td>接受后不可改历史</td></tr><tr><td>Runbook</td><td>线上如何操作和恢复</td><td>随运行环境更新</td></tr><tr><td>Changelog</td><td>对消费者发生了什么变化</td><td>按发布累积</td></tr></tbody></table><p>ADR 引用 PRD 的功能与非功能需求，引用 benchmark 和 prototype 证据，再链接最终 design。它不复制所有内容。</p><h2 id="三、最小字段逐项说明" tabindex="-1">三、最小字段逐项说明 <a class="header-anchor" href="#三、最小字段逐项说明" aria-label="Permalink to &quot;三、最小字段逐项说明&quot;">​</a></h2><h3 id="_1-id-与标题" tabindex="-1">1. ID 与标题 <a class="header-anchor" href="#_1-id-与标题" aria-label="Permalink to &quot;1. ID 与标题&quot;">​</a></h3><p>ID 稳定、唯一、不复用。标题写决策，例如“采用 PostgreSQL 全文搜索支持第一阶段商品检索”，不是“搜索讨论”。</p><h3 id="_2-状态" tabindex="-1">2. 状态 <a class="header-anchor" href="#_2-状态" aria-label="Permalink to &quot;2. 状态&quot;">​</a></h3><p>Proposed 可评审和修改；Accepted 表示团队采用；Rejected 保留放弃理由；Deprecated 表示不建议新增使用；Superseded 表示新 ADR 接管。状态名称是团队约定，但语义必须一致。</p><h3 id="_3-context" tabindex="-1">3. Context <a class="header-anchor" href="#_3-context" aria-label="Permalink to &quot;3. Context&quot;">​</a></h3><p>记录推动决策的事实、目标、约束、未知和决策期限。写当时流量、数据量、团队能力、兼容要求和安全边界。不要把后来结果改写进旧上下文。</p><h3 id="_4-decision-drivers" tabindex="-1">4. Decision drivers <a class="header-anchor" href="#_4-decision-drivers" aria-label="Permalink to &quot;4. Decision drivers&quot;">​</a></h3><p>驱动因素应可比较：p95 延迟、相关性、运维人数、迁移窗口、成本上限、数据驻留。没有尺度的“高性能、易维护”无法排序。</p><h3 id="_5-options" tabindex="-1">5. Options <a class="header-anchor" href="#_5-options" aria-label="Permalink to &quot;5. Options&quot;">​</a></h3><p>只列真实可行方案。每项用同一输入和评估方法比较，包含保持现状。明显不可用的陪衬方案会制造虚假合理性。</p><h3 id="_6-decision" tabindex="-1">6. Decision <a class="header-anchor" href="#_6-decision" aria-label="Permalink to &quot;6. Decision&quot;">​</a></h3><p>明确选择、适用范围、开始时间、禁止事项和例外流程。阶段性选择拆成多个 ADR 或明确阶段边界。</p><h3 id="_7-consequences" tabindex="-1">7. Consequences <a class="header-anchor" href="#_7-consequences" aria-label="Permalink to &quot;7. Consequences&quot;">​</a></h3><p>同时写正面、负面和中性后果；负面项分配 owner、缓解任务或退出条件。选择 SaaS 还要记录数据流、供应商锁定、费用和故障依赖。</p><h3 id="_8-validation-与复审触发" tabindex="-1">8. Validation 与复审触发 <a class="header-anchor" href="#_8-validation-与复审触发" aria-label="Permalink to &quot;8. Validation 与复审触发&quot;">​</a></h3><p>定义如何判断选择有效：指标、契约测试、架构 lint、成本账单。复审由条件触发，例如数据量增长 10 倍、价格变化、浏览器支持成熟，而不是无意义地定期重写。</p><h2 id="四、从证据到决定" tabindex="-1">四、从证据到决定 <a class="header-anchor" href="#四、从证据到决定" aria-label="Permalink to &quot;四、从证据到决定&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    N[&quot;需求与约束&quot;] --&gt; D[&quot;决策驱动&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; O[&quot;可行方案&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    O --&gt; E[&quot;实验与证据&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; C[&quot;选择&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; Q[&quot;后果与任务&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q --&gt; V[&quot;验证与复审&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>先冻结比较输入。若方案 A 用 100 万文档 benchmark，方案 B 用 1 万文档宣传数据，结论不可比较。实验记录环境、数据分布、查询集、预热、并发与成本。</p><p>权重用于显式讨论，不自动产生真理。对安全硬约束使用 gate：不满足数据驻留的方案直接淘汰，不用高性能分数抵消。</p><h2 id="五、案例一-搜索索引方案" tabindex="-1">五、案例一：搜索索引方案 <a class="header-anchor" href="#五、案例一-搜索索引方案" aria-label="Permalink to &quot;五、案例一：搜索索引方案&quot;">​</a></h2><h3 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>电商后台有 800 万商品，中文名称、SKU、品牌和类目检索。当前数据库 <code>LIKE</code> 查询 p95 2.4 秒，更新后 5 分钟内可检索即可；团队只有两名后端工程师，第一年基础设施预算每月 8,000 元。</p><h3 id="drivers" tabindex="-1">Drivers <a class="header-anchor" href="#drivers" aria-label="Permalink to &quot;Drivers&quot;">​</a></h3><ol><li>p95 在 50 并发下低于 500ms。</li><li>Top-10 相关性基准 NDCG@10 不低于 0.78。</li><li>索引延迟 p99 低于 5 分钟。</li><li>支持中文分析与同义词。</li><li>两人可值守，满足预算。</li></ol><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><p>A：PostgreSQL FTS/pg_trgm；B：自管 OpenSearch；C：托管搜索服务；D：维持 LIKE 并优化索引。</p><h3 id="evidence" tabindex="-1">Evidence <a class="header-anchor" href="#evidence" aria-label="Permalink to &quot;Evidence&quot;">​</a></h3><p>使用脱敏后的 100 万商品、200 条标注查询和 50 并发压测。PostgreSQL p95 620ms/NDCG 0.70；OpenSearch 210ms/0.82 但预计值守高；托管服务 190ms/0.81、月估算 6,500 元；LIKE 1.3s/0.52。</p><h3 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h3><p>第一阶段采用托管搜索服务，通过 SearchPort 隔离供应商 API。商品写入后通过 outbox 同步；搜索不可用时后台允许按精确 SKU 回退，不自动返回不完整全文结果。</p><h3 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><p>满足延迟与相关性；增加供应商依赖和索引对账；需要字段脱敏、重建脚本、预算告警和降级 runbook。三个月内建立双读相关性报告。</p><h3 id="trigger" tabindex="-1">Trigger <a class="header-anchor" href="#trigger" aria-label="Permalink to &quot;Trigger&quot;">​</a></h3><p>月费用超过 8,000 元、数据驻留要求变化、p95 连续一周超 500ms 或供应商能力不满足同义词管理时提出新 ADR。</p><h3 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h3><p>阻断搜索服务，验证 SKU 回退、错误提示和核心编辑流程；制造 outbox 重复与乱序，确认 document version 防止旧索引覆盖。</p><h2 id="六、案例二-第三方支付接入" tabindex="-1">六、案例二：第三方支付接入 <a class="header-anchor" href="#六、案例二-第三方支付接入" aria-label="Permalink to &quot;六、案例二：第三方支付接入&quot;">​</a></h2><h3 id="context-1" tabindex="-1">Context <a class="header-anchor" href="#context-1" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>产品需要订阅支付和退款，首发两个地区。决定不是“选哪个 SDK”，而是选择支付能力边界、商户责任、数据合规和故障模型。</p><h3 id="hard-gates" tabindex="-1">Hard gates <a class="header-anchor" href="#hard-gates" aria-label="Permalink to &quot;Hard gates&quot;">​</a></h3><p>供应商必须支持目标地区、服务端确认、幂等请求、webhook 签名、退款和合规数据处理。不满足任一 gate 的方案淘汰。</p><h3 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h3><p>比较交易费率、结算周期、拒付工具、sandbox、SLA、数据出口、webhook 重放、迁移 token 能力和退出成本。费用按预估交易分布计算，不只比较宣传百分比。</p><h3 id="decision-1" tabindex="-1">Decision <a class="header-anchor" href="#decision-1" aria-label="Permalink to &quot;Decision&quot;">​</a></h3><p>使用供应商 P，通过 PaymentPort 隔离；浏览器 SDK 只采集受控支付信息；订单成功以服务端 API/webhook 对账为准；所有创建使用幂等键；timeout 进入 unknown。</p><h3 id="negative-consequences" tabindex="-1">Negative consequences <a class="header-anchor" href="#negative-consequences" aria-label="Permalink to &quot;Negative consequences&quot;">​</a></h3><p>供应商故障阻断新支付；token 不完全可迁移；退款状态依赖 webhook。缓解包括 circuit/降级、人工对账、事件重放和合同退出条款。</p><h3 id="supersede-场景" tabindex="-1">Supersede 场景 <a class="header-anchor" href="#supersede-场景" aria-label="Permalink to &quot;Supersede 场景&quot;">​</a></h3><p>两年后新增地区不受支持。不能编辑旧 ADR 写成“选择 Q”；创建新 ADR，引用新增地区、迁移能力和双轨期，旧 ADR 标 Superseded 并链接新记录。</p><h2 id="七、状态与不可变历史" tabindex="-1">七、状态与不可变历史 <a class="header-anchor" href="#七、状态与不可变历史" aria-label="Permalink to &quot;七、状态与不可变历史&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">stateDiagram-v2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    [*] --&gt; Proposed</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Proposed --&gt; Accepted: 评审通过</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Proposed --&gt; Rejected: 放弃并记录原因</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Accepted --&gt; Deprecated: 不再用于新增</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Accepted --&gt; Superseded: 新 ADR 接管</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Deprecated --&gt; Superseded: 完成替代决策</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>AWS 与 Microsoft 指南都强调已接受记录不回写历史。可修复拼写或坏链接，但不能改当时理由和结论；实质变化创建新记录。</p><h2 id="八、评审流程" tabindex="-1">八、评审流程 <a class="header-anchor" href="#八、评审流程" aria-label="Permalink to &quot;八、评审流程&quot;">​</a></h2><ol><li>指定 owner 和决策期限。</li><li>Proposed ADR 在评审前提供阅读时间。</li><li>评审者逐条关联 evidence 与 driver。</li><li>未决动作有负责人；需要补证据则保持 Proposed。</li><li>Accepted 后记录参与者、日期和实现任务。</li><li>代码评审发现违反 ADR 时链接记录，修改代码或提出 superseding ADR。</li></ol><p>置信度可记录 high/medium/low。低置信但必须及时决定时，缩小可逆范围、设置更近复审 trigger 和实验。</p><h2 id="九、把决定变成可执行约束" tabindex="-1">九、把决定变成可执行约束 <a class="header-anchor" href="#九、把决定变成可执行约束" aria-label="Permalink to &quot;九、把决定变成可执行约束&quot;">​</a></h2><p>ADR 决定模块方向后，ESLint/Nx rule 链接 ADR ID；决定 API 兼容后，契约测试和 schema diff 执行；决定预算后，成本告警执行。没有自动化的规则仍需评审清单和 owner。</p><p>后果任务进入 backlog，包含迁移、监控、runbook 和删除兼容层。只写在 ADR 中不会自动完成。</p><h2 id="十、decision-log-与检索" tabindex="-1">十、Decision log 与检索 <a class="header-anchor" href="#十、decision-log-与检索" aria-label="Permalink to &quot;十、Decision log 与检索&quot;">​</a></h2><p>索引显示 ID、标题、状态、日期、owner、supersedes/supersededBy 和标签。按领域、质量属性、供应商检索。ID 不因目录移动改变。</p><p>CI 检查 frontmatter、编号唯一、本地链接、Accepted 必含 consequences/validation、supersede 双向链接。结构检查不能证明理由正确，但能阻止断链。</p><h2 id="十一、常见失败" tabindex="-1">十一、常见失败 <a class="header-anchor" href="#十一、常见失败" aria-label="Permalink to &quot;十一、常见失败&quot;">​</a></h2><table tabindex="0"><thead><tr><th>失败</th><th>后果</th><th>修正</th></tr></thead><tbody><tr><td>只有结论</td><td>无法判断何时失效</td><td>写上下文和 drivers</td></tr><tr><td>只列优点</td><td>成本无人承担</td><td>负面后果和 owner</td></tr><tr><td>方案不是同一输入</td><td>比较失真</td><td>统一 benchmark</td></tr><tr><td>Accepted 后改正文</td><td>历史被覆盖</td><td>新 ADR supersede</td></tr><tr><td>每个小决定都写</td><td>日志噪音</td><td>建显著性阈值</td></tr><tr><td>ADR 代替设计文档</td><td>细节膨胀且结论不清</td><td>链接补充设计</td></tr><tr><td>没有执行约束</td><td>决定被绕过</td><td>lint/test/评审 gate</td></tr></tbody></table><h2 id="十二、安全与公开边界" tabindex="-1">十二、安全与公开边界 <a class="header-anchor" href="#十二、安全与公开边界" aria-label="Permalink to &quot;十二、安全与公开边界&quot;">​</a></h2><p>公开仓库 ADR 不写密钥、未披露漏洞、合同机密和个人数据。可记录决策所需的脱敏事实，受限证据放权限受控系统并使用稳定引用。</p><p>供应商选择记录数据类别、传输地区、删除能力和 breach 责任，但具体凭证留在密钥系统。</p><h2 id="十三、决策矩阵与证据强度" tabindex="-1">十三、决策矩阵与证据强度 <a class="header-anchor" href="#十三、决策矩阵与证据强度" aria-label="Permalink to &quot;十三、决策矩阵与证据强度&quot;">​</a></h2><p>搜索方案的评分保留原始值，不只保留总分：</p><table tabindex="0"><thead><tr><th>Driver</th><th style="text-align:right;">Gate/权重</th><th style="text-align:right;">PostgreSQL</th><th style="text-align:right;">OpenSearch</th><th style="text-align:right;">托管搜索</th></tr></thead><tbody><tr><td>数据驻留</td><td style="text-align:right;">Gate</td><td style="text-align:right;">通过</td><td style="text-align:right;">通过</td><td style="text-align:right;">通过</td></tr><tr><td>NDCG@10</td><td style="text-align:right;">30%</td><td style="text-align:right;">0.70</td><td style="text-align:right;">0.82</td><td style="text-align:right;">0.81</td></tr><tr><td>p95</td><td style="text-align:right;">25%</td><td style="text-align:right;">620ms</td><td style="text-align:right;">210ms</td><td style="text-align:right;">190ms</td></tr><tr><td>月成本</td><td style="text-align:right;">20%</td><td style="text-align:right;">2,000</td><td style="text-align:right;">5,500</td><td style="text-align:right;">6,500</td></tr><tr><td>值守负担</td><td style="text-align:right;">25%</td><td style="text-align:right;">中</td><td style="text-align:right;">高</td><td style="text-align:right;">低</td></tr></tbody></table><p>权重做敏感性分析。若成本权重从 20% 到 40% 就改变结论，ADR 要记录预算不确定性和复审条件。Gate 不参与加权，不满足直接淘汰。</p><p>证据强度区分供应商声明、实验 benchmark、脱敏生产回放和真实灰度。低置信证据对应更小初始范围和更强退出接缝。</p><h2 id="十四、poc-的边界" tabindex="-1">十四、POC 的边界 <a class="header-anchor" href="#十四、poc-的边界" aria-label="Permalink to &quot;十四、POC 的边界&quot;">​</a></h2><p>POC 回答一个关键未知，例如中文相关性或 webhook 乱序，不是缩小版生产系统。它记录假设、数据、环境、通过阈值和销毁日期。</p><p>POC 代码通常缺少授权、错误处理、可观测性、容量和升级策略，不能直接复制到生产。ADR 使用 POC 结果作为证据，生产设计另行完成。</p><p>未达到 gate 时记录 Rejected 及原因，不能事后调低阈值证明偏好，也不能只保存成功截图。</p><h2 id="十五、成本与退出量化" tabindex="-1">十五、成本与退出量化 <a class="header-anchor" href="#十五、成本与退出量化" aria-label="Permalink to &quot;十五、成本与退出量化&quot;">​</a></h2><p>成本包含许可、基础设施、传输、值守、培训、迁移和停机风险。SaaS 按请求和存储分布计算；自管方案计入工程师值班与升级时间。</p><p>退出成本列出数据格式、token/身份迁移、双写时长、消费者改造数和合同期限。声称“可替换”需要第二适配器或契约测试证明。</p><p>采用后将真实成本与估算比较，偏差超过阈值触发复审，检查输入变化或估算错误。</p><h2 id="十六、综合练习" tabindex="-1">十六、综合练习 <a class="header-anchor" href="#十六、综合练习" aria-label="Permalink to &quot;十六、综合练习&quot;">​</a></h2><p>为“前端采用单体仓库还是多仓库”写 Proposed ADR。用真实模块数、发布频率、权限隔离、构建时长和团队边界比较至少三方案。</p><h3 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h3><ul><li>[ ] 决策达到团队的架构显著性阈值。</li><li>[ ] Context、drivers 和 hard gates 可验证。</li><li>[ ] 至少三个可行方案使用同一输入比较。</li><li>[ ] 正负后果都有 owner 或退出条件。</li><li>[ ] Decision 写清范围、禁止事项和例外。</li><li>[ ] Validation 连接到指标、测试或 lint。</li><li>[ ] Supersede 流程保持旧记录不变。</li><li>[ ] 内容不含密钥和受限证据。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://docs.aws.amazon.com/prescriptive-guidance/latest/architectural-decision-records/adr-process.html" target="_blank" rel="noreferrer">AWS：Architectural decision record process</a>（访问日期：2026-07-18）</li><li><a href="https://learn.microsoft.com/en-us/azure/well-architected/architect-role/architecture-decision-record" target="_blank" rel="noreferrer">Microsoft Azure：Maintain an architecture decision record</a>（访问日期：2026-07-18）</li><li><a href="https://docs.aws.amazon.com/prescriptive-guidance/latest/architectural-decision-records/introduction.html" target="_blank" rel="noreferrer">AWS：Using ADRs to streamline decision-making</a>（访问日期：2026-07-18）</li></ul>`,95)])])}const b=a(s,[["render",n]]);export{u as __pageData,b as default};
